INSERT INTO patterns (pattern, response, domain, metadata) VALUES
('Aurora FALCON AI Control System', 'Aurora Flight Sciences (Boeing) demonstrated its AI-enabled FALCON (Fast Adaptation and Learning for Control Online) technology under DARPA LINC program, achieving 94% safe-zone performance and 61% faster recovery during simulated maritime hazards.', 'ai_control', '{"company": "Aurora Flight Sciences", "parent": "Boeing", "program": "DARPA LINC", "safe_zone": "94%", "recovery_improvement": "61%", "application": "maritime_safety"}'),
('India Sovereign AI Initiative', 'India AI Impact Summit drew 250,000+ registered attendees and $250B+ investment pledges. Reliance announced $110B investment over 7 years for AI infrastructure. Microsoft committed $50B by end of decade for Global South AI capabilities.', 'ai_policy', '{"event": "AI Impact Summit", "location": "New Delhi", "attendees": 250000, "investment": "$250B", "reliance_commitment": "$110B", "microsoft_commitment": "$50B"}'),
('Sarvam AI Large Models India', 'Bengaluru-based Sarvam AI launched LLMs with 30B and 105B parameters using mixture-of-experts architectures trained on domestic Indian compute infrastructure, advancing sovereign AI capabilities.', 'ai_models', '{"company": "Sarvam AI", "location": "Bengaluru", "parameters": [30000000000, 105000000000], "architecture": "mixture_of_experts", "training": "domestic_compute"}'),
('US Tech Corps AI Export', 'White House launched Tech Corps within Peace Corps to export American AI abroad, implementing AI solutions for agriculture, education, health, and economic development in partner nations.', 'ai_policy', '{"country": "USA", "initiative": "Tech Corps", "parent_program": "Peace Corps", "sectors": ["agriculture", "education", "health", "economic_development"]}'),
('Teen AI Entrepreneur Surge', 'Teen founders are increasingly launching AI startups, with examples including Delv AI (14-year-old founder), Synthetic Sciences ($1.5M raised from Y Combinator), representing a generational shift in AI entrepreneurship.', 'ai_economics', '{"trend": "teen_founders", "example_companies": ["Delv AI", "Synthetic Sciences"], "funding": "$1.5M", "accelerator": "Y Combinator"}'),
('Agentic AI Healthcare Transformation', 'Healthcare organizations shifting from generative AI documentation to agentic AI systems that execute end-to-end workflows like prior authorization and clinical trial coordination, addressing administrative fragmentation.', 'ai_healthcare', '{"shift": "generative_to_agentic", "applications": ["prior_authorization", "clinical_trials"], "benefit": "end_to_end_automation"}'),
('India AI Agriculture Living Lab', 'Maharashtra endorsed as global living lab for AI in agriculture at AI4Agri2026 Summit. MahaVISTAAR platform scaling to Bharat Vistaar for climate-resilient, farmer-centric AI innovation.', 'ai_agriculture', '{"location": "Maharashtra", "event": "AI4Agri2026", "platform": ["MahaVISTAAR", "Bharat Vistaar"], "focus": "climate_resilient_agriculture", "voice_ai": true}'),
('AI Farm Advisory Value India', 'India 140M farm holdings could generate Rs 70,000 crore annual value if AI advisories help each farmer save Rs 5,000/year through better input timing, pest prediction, and market linkage.', 'ai_agriculture', '{"country": "India", "farm_holdings": "140M", "potential_value": "Rs 70,000 crore", "per_farmer_savings": "Rs 5,000", "benefits": ["input_timing", "pest_prediction", "market_linkage"]}'),
('Anthropic Claude Sonnet 4.6 Release', 'Anthropic released Claude Sonnet 4.6 with 1M token context window, improved coding abilities matching previous Opus performance, and enhanced computer use capabilities. Achieves human baseline on OSWorld benchmark.', 'ai_models', '{"company": "Anthropic", "model": "Claude Sonnet 4.6", "context_window": "1M tokens", "benchmark": "OSWorld", "performance": "human_baseline", "improvements": ["coding", "instruction_following", "computer_use"]}'),
('Claude Code Security Launch', 'Anthropic launched Claude Code Security for AI-powered vulnerability scanning that reasons through codebases like human security researchers, tracing data flows and flagging vulnerabilities missed by rule-based tools.', 'ai_security', '{"company": "Anthropic", "product": "Claude Code Security", "capability": "vulnerability_scanning", "approach": "reasoning_based", "advantage": "beyond_static_analysis"}'),
('Claude Opus 4.6 Autonomy', 'Anthropic Opus 4.6 demonstrates improved agentic capabilities for investigating security flaws and using various tools to test code, showing meaningful autonomy improvements over previous versions.', 'ai_models', '{"company": "Anthropic", "model": "Opus 4.6", "capability": "agentic_behavior", "applications": ["security_investigation", "code_testing"], "improvement": "autonomy"}'),
('Google Gemini 3.1 Pro Release', 'Google released Gemini 3.1 Pro on Feb 20, 2026 with 77.1% on ARC-AGI-2 benchmark and roughly double the reasoning performance of Gemini 3 Pro, representing strategic shift to targeted reasoning improvements.', 'ai_models', '{"company": "Google", "model": "Gemini 3.1 Pro", "release_date": "2026-02-20", "benchmark": "ARC-AGI-2", "score": "77.1%", "reasoning_improvement": "2x", "focus": "reasoning"}'),
('Gemini 3.1 Pro Multimodal', 'Gemini 3.1 Pro demonstrates improved multimodal capabilities for understanding spatial relationships, shape mapping, and visual problem-solving, plus animated code-based graphics generation.', 'ai_models', '{"company": "Google", "model": "Gemini 3.1 Pro", "capabilities": ["spatial_reasoning", "shape_mapping", "visual_problem_solving", "animated_graphics"], "multimodal": true}'),
('Infosys Anthropic Enterprise Partnership', 'Infosys and Anthropic announced strategic collaboration integrating Claude models with Infosys Topaz for enterprise AI in telecom, financial services, manufacturing, and software development.', 'ai_enterprise', '{"companies": ["Infosys", "Anthropic"], "platform": "Infosys Topaz", "models": "Claude", "industries": ["telecom", "finance", "manufacturing", "software"], "focus": "governance_transparency"}'),
('Software Stock Selloff AI Disruption', 'Anthropic Claude releases triggered global selloff in software stocks including Oracle and Adobe, as investors grow concerned about AI disruption of traditional software business models.', 'ai_economics', '{"trigger": "Claude releases", "impact": "software_stock_decline", "affected": ["Oracle", "Adobe", "Indian IT firms", "Nomura Research"], "concern": "AI_disruption"}'),
